      const supabase = getSupabase();
      if (!supabase) {
          console.error("Supabase client not available. Cannot send contact request.");
          return { success: false };
      }

      try {
          const { error } = await supabase.from('contact_requests').insert({ name, email, message });
          if (error) throw error;

          onContactAdmin(
              { name, email, avatar: `https://i.pravatar.cc/150?u=${email}`, role: 'user' },
              message
          );

          return { success: true };
      } catch (error) {
