      const admin = allUsers.find(u => u.email === 'ragow49@gmail.com') || allUsers.find(u => u.role === 'admin');
      return admin || user; 
  }, [allUsers, user]);

  const isOwner = user.id === profileOwner.id;

  useEffect(() => {
    const fetchProfile = async () => {
        try {
            const profile = await getWorkProfile(profileOwner.id);
            if (profile) {
                setWorkProfile(profile);
            } else {
                setWorkProfile({
                    user_id: profileOwner.id,
                    display_name: profileOwner.name,
                    avatar_url: profileOwner.avatar,
                    role_title: profileOwner.role === 'admin' ? 'Administrator' : 'Member',
                    bio: profileOwner.bio || "Hello! I'm a passionate researcher exploring the depths of cybersecurity and technology.",
                    skills: profileOwner.skills || [],
                    social_links: { email: profileOwner.email },
                    education: [],
                    experience: [],
                    internships: [],
                    projects: [],
                    achievements: [],
                    certifications: [],
                    services: [],
                    summary: '',
                    what_i_do: ''
                });
            }
        } catch (error) {
            console.error("Failed to fetch work profile:", error);
        } finally {
            setLoading(false);
        }
    };
    if (profileOwner) fetchProfile();
  }, [profileOwner]);

  // Real-time Sync for MyWork Profile
  useEffect(() => {
    const supabase = getSupabase();
    if (!supabase || !profileOwner || isUsingMockData()) return;

    const channel = supabase.channel(`public:work_profiles:user_id=eq.${profileOwner.id}`)
        .on('postgres_changes', { 
            event: '*', 
            schema: 'public', 
            table: 'work_profiles', 
            filter: `user_id=eq.${profileOwner.id}` 
        }, (payload) => {
            console.log('[Realtime] Received profile update:', payload);
            if (payload.new) {
                setWorkProfile(prev => ({ ...prev, ...(payload.new as WorkProfile) }));
            }
        })
        .subscribe((status) => {
            if (status === 'SUBSCRIBED') console.log('[Realtime] Subscribed to profile updates');
        });

    return () => { supabase.removeChannel(channel); };
  }, [profileOwner]);

  const handleSave = async (updatedData: Partial<WorkProfile>) => {
      try {
          const updatedProfile = await updateWorkProfile(profileOwner.id, updatedData);
          if (updatedProfile) {
              setWorkProfile(updatedProfile);
              addNotification({ title: 'Success', message: 'Work profile updated.', type: 'success' });
          }
      } catch (error) {
          addNotification({ title: 'Error', message: 'Failed to update profile.', type: 'error' });
      }
  };

  const handleDownloadCV = async () => {
      const cvUrl = "https://gowthamsportfolio.netlify.app/assets/img/cv.pdf";
      const filename = `${workProfile?.display_name?.replace(/\s+/g, '_') || 'Resume'}_CV.pdf`;

      try {
          const response = await fetch(cvUrl);
          if (!response.ok) throw new Error('Download failed');

          const blob = await response.blob();
          const url = window.URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = filename;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          window.URL.revokeObjectURL(url);
      } catch (error) {
          console.error("Direct download failed, attempting fallback", error);
          window.open(cvUrl, '_blank');
      }
  };

  if (loading) return <div className="h-full w-full flex items-center justify-center"><SpinnerIcon className="w-12 h-12 text-indigo-500 animate-spin" /></div>;
  if (!workProfile) return null;

  const { display_name, role_title, avatar_url, bio, summary, what_i_do, services, social_links, skills, education, experience, internships, projects, achievements, certifications } = workProfile;
