                                        />
                                        {isAdminVerified && (
                                            <div className="absolute bottom-1 right-1 bg-white dark:bg-slate-800 rounded-full p-1.5 shadow-md" title="Verified Admin">
                                                <img src={getCloudinaryUrl("https://gowthamsportfolio.netlify.app/assets/img/tick.gif", { width: 20, height: 20 })} className="w-5 h-5" alt="Verified" />
                                            </div>
                                        )}
                                    </div>

                                    <h1 className="text-2xl font-extrabold text-slate-900 dark:text-white mb-1">{display_name}</h1>
                                    <p className="text-indigo-600 dark:text-indigo-400 font-bold uppercase text-xs tracking-widest mb-4">{role_title}</p>
                                    <p className="text-slate-600 dark:text-slate-300 text-sm mb-6 leading-relaxed italic">
                                        {bio}
