  searchQuery: string;
  setSearchQuery: (q: string) => void;
  sortBy: 'created_at' | 'liked_by' | 'comments';
  setSortBy: (s: 'created_at' | 'liked_by' | 'comments') => void;
  filteredAndSortedPosts: Post[];
