                        </header>

                        {selectedPost ? (
                            <div className="flex flex-col min-h-full">
                                <header className="p-4 sm:p-6 md:p-8 border-b border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50">
