                <div className="group relative">
                    <div className={`flex flex-col ${isCurrentUser ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-xs sm:max-w-md md:max-w-lg p-3 rounded-lg ${isCurrentUser ? 'bg-indigo-100/50 dark:bg-indigo-900/40 backdrop-blur-sm text-indigo-800 dark:text-indigo-200' : 'bg-white/50 dark:bg-slate-800/50 backdrop-blur-sm'}`}>
                            {!isCurrentUser && (
                                <div className="flex items-center gap-1 mb-1">
                                    <p className="text-xs font-bold text-indigo-500 dark:text-indigo-400">{msg.author.name}</p>
