                                            }`}
                                            title={userNames}
                                        >
                                            <span className="text-xs">{emoji}</span>
                                            <span className={`text-xs font-semibold ${userReacted ? 'text-indigo-600 dark:text-indigo-200' : 'text-slate-600 dark:text-slate-300'}`}>{users.length}</span>
                                        </button>
