                                })}
                            </div>
                        )}
                    </div>

                    {(canEdit || canDelete || !isCurrentUser) && !isEditing && (
                        <div className={`
                            absolute z-10
                            bottom-full mb-1 sm:top-1/2 sm:bottom-auto sm:mb-0 sm:-translate-y-1/2
