const ProfileSettings: React.FC<{user: User, onSave: (updatedUser: Partial<User>, silent?: boolean) => Promise<void>, onOpenApp: (appId: string, props?: Record<string, any>) => void}> = ({ user, onSave, onOpenApp }) => {
    const [isAvatarUploading, setIsAvatarUploading] = useState(false);
    const avatarInputRef = useRef<HTMLInputElement>(null);
    const { addNotification } = useNotificationState();
    const [isEditingName, setIsEditingName] = useState(false);
    const [displayName, setDisplayName] = useState(user.name);
    const [displayNameSaveState, setDisplayNameSaveState] = useState<'idle' | 'saving' | 'saved'>('idle');
    const [bio, setBio] = useState(user.bio || '');
    const [bioSaveState, setBioSaveState] = useState<'idle' | 'saving' | 'saved'>('idle');
    const [gender, setGender] = useState<User['gender']>(user.gender || 'Other');
    const [skills, setSkills] = useState(user.skills || []);
    const [skillInput, setSkillInput] = useState('');
    const [isPrivate, setIsPrivate] = useState(user.is_profile_private || false);

    const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setIsAvatarUploading(true);
        try {
            const imageUrl = await uploadToCloudinary(file);
            await onSave({ avatar: imageUrl }, true);
            addNotification({ title: 'Success', message: 'Profile picture updated!', type: 'success' });
        } catch (error) {
            addNotification({ title: 'Upload Failed', message: 'Could not upload profile picture.', type: 'error' });
        } finally {
            setIsAvatarUploading(false);
        }
    };

    const handleSaveDisplayName = async () => { if (!displayName.trim()) return; setDisplayNameSaveState('saving'); await onSave({ name: displayName }); setDisplayNameSaveState('saved'); setIsEditingName(false); setTimeout(() => setDisplayNameSaveState('idle'), 2000); };
    const handleSaveBio = async () => { setBioSaveState('saving'); await onSave({ bio: bio }); setBioSaveState('saved'); setTimeout(() => setBioSaveState('idle'), 2000); };
    const handleGenderChange = async (newGender: User['gender']) => { setGender(newGender); await onSave({ gender: newGender }, true); };
    const handleAddSkill = (e: React.KeyboardEvent<HTMLInputElement>) => { if ((e.key === 'Enter' || e.key === ',') && skillInput.trim() && skills.length < 10) { e.preventDefault(); const newSkill = skillInput.trim(); if (!skills.includes(newSkill)) { const newSkills = [...skills, newSkill]; setSkills(newSkills); onSave({ skills: newSkills }, true); } setSkillInput(''); } };
    const handleRemoveSkill = (skillToRemove: string) => { const newSkills = skills.filter(skill => skill !== skillToRemove); setSkills(newSkills); onSave({ skills: newSkills }, true); };
    const handlePrivacyToggle = async () => { const newIsPrivate = !isPrivate; setIsPrivate(newIsPrivate); await onSave({ is_profile_private: newIsPrivate }, true); addNotification({ title: 'Privacy Updated', message: `Profile is now ${newIsPrivate ? 'private' : 'public'}.`, type: 'success', duration: 3000 }); };

    return (
        <div className="max-w-4xl mx-auto space-y-8">
            <div className="bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm rounded-lg shadow-sm border border-slate-200 dark:border-slate-700 p-4 sm:p-5 flex items-center gap-4 sm:gap-5">
                <div className="relative w-16 h-16 sm:w-20 sm:h-20 group flex-shrink-0">
                    <img src={getCloudinaryUrl(user.avatar, { width: 128, height: 128, radius: 'max' })} alt={displayName} className="w-full h-full rounded-full shadow-md" />
                    <input type="file" ref={avatarInputRef} onChange={handleAvatarUpload} hidden accept="image/*" />
