const FriendManagement: React.FC<{
    allUsers: User[];
    currentUser: User;
    onSendFriendRequest: (from: User, toEmail: string) => void;
    onAccept: (req: { email: string; name: string }) => void;
    onReject: (req: { email: string; name: string }) => void;
    onRemove: (friend: { email: string; name: string }) => void;
}> = ({ allUsers, currentUser, onSendFriendRequest, onAccept, onReject, onRemove }) => {
    const [searchEmail, setSearchEmail] = useState('');
    const { addNotification } = useNotificationState();

    const handleSendRequest = () => {
        if (!searchEmail.trim()) return;
        const target = allUsers.find(u => u.email === searchEmail.trim() || u.name.toLowerCase() === searchEmail.trim().toLowerCase());
        if (!target) {
            addNotification({ title: 'User not found', message: 'Could not find a user with that email or name.', type: 'error' });
            return;
        }
        if (target.id === currentUser.id) {
            addNotification({ title: 'Invalid Request', message: 'You cannot add yourself.', type: 'warning' });
            return;
        }
        if (currentUser.friends?.includes(target.email)) {
            addNotification({ title: 'Already Friends', message: 'You are already friends with this user.', type: 'info' });
            return;
        }
        onSendFriendRequest(currentUser, target.email);
        setSearchEmail('');
        addNotification({ title: 'Request Sent', message: `Friend request sent to ${target.name}.`, type: 'success' });
    };

    return (
        <div className="space-y-8">
            <SettingsCard title="Add Friend">
                <div className="flex gap-2">
                    <input 
                        type="text" 
                        value={searchEmail} 
                        onChange={(e) => setSearchEmail(e.target.value)} 
                        placeholder="Enter email or username..." 
                        className="modern-input flex-1"
                        onKeyDown={(e) => e.key === 'Enter' && handleSendRequest()}
                    />
                    <button onClick={handleSendRequest} className="btn">Add</button>
                </div>
            </SettingsCard>

            <SettingsCard title="Friend Requests">
                {currentUser.friend_requests && currentUser.friend_requests.length > 0 ? (
                    <div className="space-y-3">
                        {currentUser.friend_requests.map(email => {
                            const user = allUsers.find(u => u.email === email);
                            if (!user) return null;
                            return (
                                <div key={email} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900/50 rounded-lg">
                                    <div className="flex items-center gap-3">
                                        <img src={getCloudinaryUrl(user.avatar, { width: 40, height: 40, radius: 'max' })} alt={user.name} className="w-10 h-10 rounded-full" />
                                        <div>
                                            <p className="font-semibold text-slate-800 dark:text-slate-100">{user.name}</p>
                                            <p className="text-xs text-slate-500">{user.email}</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => onReject({ email, name: user.name })} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors"><XCircleIcon className="w-5 h-5"/></button>
                                        <button onClick={() => onAccept({ email, name: user.name })} className="p-2 text-green-500 hover:bg-green-50 dark:hover:bg-green-900/20 rounded-md transition-colors"><CheckCircleIcon className="w-5 h-5"/></button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <p className="text-slate-500 text-sm">No pending friend requests.</p>
                )}
            </SettingsCard>

            <SettingsCard title={`Friends (${currentUser.friends?.length || 0})`}>
                {currentUser.friends && currentUser.friends.length > 0 ? (
                    <div className="space-y-3">
                        {currentUser.friends.map(email => {
                            const user = allUsers.find(u => u.email === email);
                            // Handle cases where friend might be deleted or data is syncing
                            const name = user?.name || email.split('@')[0];
                            const avatar = user?.avatar || `https://i.pravatar.cc/150?u=${email}`;

                            return (
                                <div key={email} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900/50 rounded-lg group">
                                    <div className="flex items-center gap-3">
                                        <img src={getCloudinaryUrl(avatar, { width: 40, height: 40, radius: 'max' })} alt={name} className="w-10 h-10 rounded-full" />
                                        <div>
                                            <p className="font-semibold text-slate-800 dark:text-slate-100">{name}</p>
                                            <p className="text-xs text-slate-500">{email}</p>
                                        </div>
                                    </div>
                                    <button onClick={() => onRemove({ email, name })} className="px-3 py-1.5 text-xs font-semibold text-red-600 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 dark:hover:bg-red-900/40 rounded-md opacity-0 group-hover:opacity-100 transition-all">Remove</button>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <p className="text-slate-500 text-sm">You haven't added any friends yet.</p>
                )}
            </SettingsCard>
        </div>
    );
};

const AccountSettings: React.FC<{
    user: User;
    onDeleteAccount: () => Promise<string | void>;
    onVerifyPassword: (password: string) => Promise<boolean>;
    onEmailChange: (newEmail: string) => Promise<string | void>;
    onProfileUpdate: (updatedData: Partial<User>) => Promise<void>;
}> = ({ user, onDeleteAccount, onVerifyPassword, onEmailChange, onProfileUpdate }) => {
    const [isDeleting, setIsDeleting] = useState(false);
    const [deleteConfirmPassword, setDeleteConfirmPassword] = useState('');
    const [deleteError, setDeleteError] = useState<string | null>(null);
    const { addNotification } = useNotificationState();

    // Email Change State
    const [newEmail, setNewEmail] = useState('');
    const [currentPassword, setCurrentPassword] = useState('');
    const [isEmailChanging, setIsEmailChanging] = useState(false);
    const [emailChangeError, setEmailChangeError] = useState<string | null>(null);

    // 2FA State
    const [is2FAModalOpen, setIs2FAModalOpen] = useState(false);
    const [backupCodes, setBackupCodes] = useState<string[]>([]);
    const [showBackupCodes, setShowBackupCodes] = useState(false);
    const [passwordFor2FA, setPasswordFor2FA] = useState('');
    const [isVerifying2FAPassword, setIsVerifying2FAPassword] = useState(false);

    const handleDelete = async () => {
        if (!deleteConfirmPassword) return;

        const isValid = await onVerifyPassword(deleteConfirmPassword);
        if (!isValid) {
            setDeleteError("Incorrect password.");
            return;
        }

        const error = await onDeleteAccount();
        if (error) setDeleteError(error as string);
    };

    const handleEmailUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newEmail || !currentPassword) return;

        setIsEmailChanging(true);
        setEmailChangeError(null);

        try {
            const isValid = await onVerifyPassword(currentPassword);
            if (!isValid) throw new Error("Incorrect current password.");

            const error = await onEmailChange(newEmail);
            if (error) throw new Error(error as string);

            addNotification({ title: 'Success', message: 'Verification email sent to new address.', type: 'success' });
            setNewEmail('');
            setCurrentPassword('');
        } catch (err: any) {
            setEmailChangeError(err.message);
        } finally {
            setIsEmailChanging(false);
        }
    };

    const handleToggle2FA = async () => {
        const isEnabling = !user.is_2fa_enabled;

        // If enabling, generate codes and show modal
        if (isEnabling) {
            const codes = Array.from({ length: 3 }, () => generateAlphanumericCode(6));
            await onProfileUpdate({ is_2fa_enabled: true, backup_codes: codes });
            setBackupCodes(codes);
            setIs2FAModalOpen(true); // Show codes immediately
            addNotification({ title: '2FA Enabled', message: 'Two-Factor Authentication is now active.', type: 'success' });
        } else {
            // Disabling
            await onProfileUpdate({ is_2fa_enabled: false, backup_codes: [] });
            addNotification({ title: '2FA Disabled', message: 'Two-Factor Authentication has been turned off.', type: 'info' });
        }
    };

    const handleRegenerateCodes = async () => {
        const codes = Array.from({ length: 3 }, () => generateAlphanumericCode(6));
        await onProfileUpdate({ backup_codes: codes });
        setBackupCodes(codes);
        setIs2FAModalOpen(true);
        addNotification({ title: 'Codes Regenerated', message: 'New backup codes generated. Old ones are invalid.', type: 'success' });
    };

    const handleViewCodes = async () => {
        // Require password to view existing codes
        if (!passwordFor2FA) {
            addNotification({ title: 'Password Required', message: 'Enter password to view codes.', type: 'warning' });
            return;
        }
        setIsVerifying2FAPassword(true);
        const isValid = await onVerifyPassword(passwordFor2FA);
        setIsVerifying2FAPassword(false);
        setPasswordFor2FA('');

        if (isValid) {
            setBackupCodes(user.backup_codes || []);
            setIs2FAModalOpen(true);
        } else {
            addNotification({ title: 'Access Denied', message: 'Incorrect password.', type: 'error' });
        }
    };

    return (
        <div className="space-y-8">
            <ConfirmationModal
                isOpen={isDeleting}
                onClose={() => { setIsDeleting(false); setDeleteError(null); setDeleteConfirmPassword(''); }}
                onConfirm={handleDelete}
                title="Delete Account"
                confirmText="Permanently Delete"
                confirmButtonClass="bg-red-600 hover:bg-red-700"
            >
                <div className="space-y-4">
                    <p className="text-red-600 dark:text-red-400 font-semibold bg-red-50 dark:bg-red-900/20 p-3 rounded-md text-sm border border-red-200 dark:border-red-900/50">
                        Warning: This action is irreversible. All your data, writeups, and settings will be permanently lost.
                    </p>
                    <div>
                        <label className="block text-sm font-medium mb-1">Confirm Password</label>
                        <input 
                            type="password" 
                            className="modern-input w-full" 
                            value={deleteConfirmPassword}
                            onChange={(e) => setDeleteConfirmPassword(e.target.value)}
                            placeholder="Enter your password"
                        />
                        {deleteError && <p className="text-xs text-red-500 mt-1">{deleteError}</p>}
                    </div>
                </div>
            </ConfirmationModal>

            <ConfirmationModal
                isOpen={is2FAModalOpen}
                onClose={() => setIs2FAModalOpen(false)}
                onConfirm={() => setIs2FAModalOpen(false)}
                title="Your Backup Codes"
                confirmText="I've Saved Them"
                cancelText="Close"
            >
                <div className="space-y-4">
                    <p className="text-sm text-slate-600 dark:text-slate-300">
                        Save these codes in a secure place (like a password manager). You will need them to log in if you lose access to your device. Each code can only be used once.
                    </p>
                    <div className="bg-slate-100 dark:bg-slate-800 p-4 rounded-lg border border-slate-200 dark:border-slate-700">
                        <div className="grid grid-cols-1 gap-2 text-center font-mono text-lg tracking-widest font-bold text-slate-800 dark:text-slate-100">
                            {backupCodes.map((code, i) => (
                                <div key={i} className="py-2 border-b border-slate-200 dark:border-slate-700 last:border-0">{code}</div>
                            ))}
                        </div>
                    </div>
                    <button 
                        onClick={() => { navigator.clipboard.writeText(backupCodes.join('\n')); addNotification({ title: 'Copied', message: 'Codes copied to clipboard.', type: 'success' }); }}
                        className="w-full py-2 text-sm font-semibold text-indigo-600 dark:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded transition-colors"
                    >
                        Copy to Clipboard
                    </button>
                </div>
            </ConfirmationModal>

            <SettingsCard title="Change Email">
                <form onSubmit={handleEmailUpdate} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium mb-1">New Email Address</label>
                            <input type="email" value={newEmail} onChange={e => setNewEmail(e.target.value)} className="modern-input w-full" required />
                        </div>
                        <div>
                            <label className="block text-sm font-medium mb-1">Current Password</label>
                            <input type="password" value={currentPassword} onChange={e => setCurrentPassword(e.target.value)} className="modern-input w-full" required />
                        </div>
                    </div>
                    {emailChangeError && <p className="text-xs text-red-500">{emailChangeError}</p>}
                    <div className="flex justify-end">
                        <button type="submit" disabled={isEmailChanging} className="btn bg-indigo-600 hover:bg-indigo-700 text-white">
                            {isEmailChanging ? <SpinnerIcon className="w-5 h-5"/> : 'Update Email'}
                        </button>
                    </div>
                </form>
            </SettingsCard>

            <SettingsCard title="Two-Factor Authentication (2FA)">
                <div className="flex items-center justify-between">
                    <div>
                        <div className="flex items-center gap-2">
                            <ShieldIcon className={`w-5 h-5 ${user.is_2fa_enabled ? 'text-green-500' : 'text-slate-400'}`} />
                            <p className="font-medium text-slate-800 dark:text-slate-100">Status: {user.is_2fa_enabled ? 'Enabled' : 'Disabled'}</p>
                        </div>
                        <p className="text-sm text-slate-500 dark:text-slate-400 mt-1 max-w-md">
                            Secure your account with backup codes. You will be required to enter a code when logging in from a new device.
                        </p>
                    </div>
                    <button 
                        onClick={handleToggle2FA}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 dark:focus:ring-offset-slate-800 ${user.is_2fa_enabled ? 'bg-indigo-600' : 'bg-slate-200 dark:bg-slate-700'}`}
                    >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${user.is_2fa_enabled ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                </div>

                {user.is_2fa_enabled && (
                    <div className="mt-6 pt-6 border-t border-slate-200 dark:border-slate-700 animate-slide-up">
                        <div className="flex flex-col sm:flex-row gap-4">
                            <div className="flex-1">
                                <h4 className="text-sm font-semibold mb-2">View Backup Codes</h4>
                                <div className="flex gap-2">
                                    <input 
                                        type="password" 
                                        value={passwordFor2FA} 
                                        onChange={e => setPasswordFor2FA(e.target.value)} 
                                        placeholder="Verify password" 
                                        className="modern-input py-1.5 text-sm flex-1"
                                    />
                                    <button onClick={handleViewCodes} disabled={isVerifying2FAPassword} className="px-3 py-1.5 bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 rounded-md text-sm font-medium transition-colors">
                                        {isVerifying2FAPassword ? <SpinnerIcon className="w-4 h-4"/> : 'View'}
                                    </button>
                                </div>
                            </div>
                            <div className="flex items-end">
                                <button onClick={handleRegenerateCodes} className="text-sm font-semibold text-indigo-600 dark:text-indigo-400 hover:underline">
                                    Regenerate System Codes
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </SettingsCard>

            <div className="border border-red-200 dark:border-red-900/30 rounded-lg p-6 bg-red-50 dark:bg-red-900/10">
