const SettingsPage: React.FC<SettingsPageProps> = ({ 
    user, allUsers, setAllUsers, 
    taskbarPosition, setTaskbarPosition, 
    desktopIconSize, setDesktopIconSize, 
    onAcceptFriendRequest, onRejectFriendRequest, onRemoveFriend, onSendFriendRequest, 
    onOpenApp, onLogout, 
    onProfileUpdate, onDeleteAccount, onVerifyPassword, onEmailChange,
    deepLinkInfo, onNavigateWithinApp 
}) => {
    const [activeSection, setActiveSection] = useState<SettingsSection>('profile');
    const { addNotification } = useNotificationState();

    useEffect(() => {
        if (deepLinkInfo) {
            const validSections: SettingsSection[] = ['profile', 'appearance', 'tools', 'friends', 'account'];
            if (validSections.includes(deepLinkInfo as SettingsSection)) {
                setActiveSection(deepLinkInfo as SettingsSection);
            }
        }
    }, [deepLinkInfo]);

    if (!user) return null; // Should not happen in protected route

    const renderContent = () => {
        switch (activeSection) {
            case 'profile':
                return <ProfileSettings user={user} onSave={onProfileUpdate} onOpenApp={onOpenApp || (() => {})} />;
            case 'appearance':
                return <AppearanceSettings 
                    taskbarPosition={taskbarPosition} 
                    setTaskbarPosition={setTaskbarPosition} 
                    desktopIconSize={desktopIconSize}
                    setDesktopIconSize={setDesktopIconSize}
                    onProfileUpdate={onProfileUpdate}
                />;
            case 'tools':
                return <ToolsSettings />;
            case 'friends':
                return <FriendManagement 
                    allUsers={allUsers} 
                    currentUser={user} 
                    onSendFriendRequest={onSendFriendRequest} 
                    onAccept={onAcceptFriendRequest} 
                    onReject={onRejectFriendRequest} 
                    onRemove={onRemoveFriend}
                />;
            case 'account':
                return <AccountSettings 
                    user={user} 
                    onDeleteAccount={onDeleteAccount}
                    onVerifyPassword={onVerifyPassword}
                    onEmailChange={onEmailChange}
                    onProfileUpdate={onProfileUpdate}
                />;
            default:
                return <ProfileSettings user={user} onSave={onProfileUpdate} onOpenApp={onOpenApp || (() => {})} />;
        }
    };

    return (
        <div className="flex flex-col md:flex-row h-full w-full bg-slate-50 dark:bg-slate-900 overflow-hidden">
            {/* Sidebar */}
            <aside className="w-full md:w-64 flex-shrink-0 border-b md:border-b-0 md:border-r border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-slate-800/50">
                <nav className="p-2">
                    <ul className="flex flex-row md:flex-col gap-1 overflow-x-auto hide-scrollbar">
                        <SettingsNavItem label="Profile" icon={<UserIcon />} isActive={activeSection === 'profile'} onClick={() => setActiveSection('profile')} />
                        <SettingsNavItem label="Appearance" icon={<PaletteIcon />} isActive={activeSection === 'appearance'} onClick={() => setActiveSection('appearance')} />
                        <SettingsNavItem label="Tools" icon={<ToolboxIcon />} isActive={activeSection === 'tools'} onClick={() => setActiveSection('tools')} />
                        <SettingsNavItem label="Friends" icon={<UsersIcon />} isActive={activeSection === 'friends'} onClick={() => setActiveSection('friends')} />
                        <SettingsNavItem label="Account" icon={<ShieldIcon />} isActive={activeSection === 'account'} onClick={() => setActiveSection('account')} />
                    </ul>
                </nav>
            </aside>

            {/* Main Content */}
            <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8 relative">
                <div className="max-w-3xl mx-auto pb-20 md:pb-0 animate-fade-in">
                    {renderContent()}
                </div>
            </main>
        </div>
    );
};

