    }[] = [
        {
            type: 'bounty', label: 'Bounty', icon: <MoneyIcon />,
            classes: { text: 'text-green-600 dark:text-green-400', ring: 'focus:ring-green-500', border: 'border-green-500', selectedBg: 'bg-green-50 dark:bg-green-900/30' },
